import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import EmployeeLayout from '../components/EmployeeLayout';
import layout2Styles from '../styles/layout2.module.css';
import buttonsStyles from '../styles/buttons.module.css';
import bookCardsStyles from '../styles/bookCards.module.css';

function InventoryPage() {
  const [books, setBooks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    const fetchBooks = async () => {
      try {
        const userInfo = JSON.parse(localStorage.getItem('userInfo'));
        const config = {
          headers: {
            Authorization: `Bearer ${userInfo.token}`,
          },
        };
        const { data } = await axios.get('/api/books', config);
        setBooks(data);
      } catch (err) {
        setError(err.response?.data?.message || 'Failed to fetch inventory');
      } finally {
        setLoading(false);
      }
    };

    fetchBooks();
  }, []);

  const formatDate = (dateString) => {
    if (!dateString) return 'N/A';
    return new Date(dateString).toLocaleDateString();
  };

  if (loading) {
    return <EmployeeLayout title="Inventory"><div>Loading...</div></EmployeeLayout>;
  }

  return (
    <EmployeeLayout title="Inventory">
      <div style={{ marginBottom: '1.5rem', display: 'flex', justifyContent: 'flex-end' }}>
        <Link to="/insertbook" className={buttonsStyles.submitButton}>Add New Book</Link>
      </div>
      {error && <p className={layout2Styles.error}>{error}</p>}
      {/* <div className={bookCardsStyles.bookContainer}> */}
        <div className={bookCardsStyles.bookCard}>
          {/* <div className={bookCardsStyles.bookDetails}> */}
            {/* <div className={bookCardsStyles.formContent}> */}
              {books.map((book) => (
                <div key={book._id} className={bookCardsStyles.bookCard}>
                  <div className={bookCardsStyles.coverArtSection}>
                    <img src={book.coverArt || '/images/cover-placeholder.png'} alt={`${book.seriesTitle} #${book.issueNumber}`} />
                  </div>
                  <div className={bookCardsStyles.formGrid}>
                    <div className={bookCardsStyles.formGroup}>
                      <label htmlFor="publisher">Publisher*:</label>
                      <input id="publisher" type="text" name="publisher" value={book.publisher || 'N/A'}/>
                    </div>
                    <div className={bookCardsStyles.formGroup}>
                      <label htmlFor="releaseDate">Release Date*:</label>
                      <input id="releaseDate" type="date" name="releaseDate" value={book.releaseDate}/>
                    </div>
                    <div className={bookCardsStyles.formGroup}>
                      <label htmlFor="seriesStartDate">Series Start Date*:</label>
                      <input id="seriesStartDate" type="date" name="seriesStartDate" value={book.seriesStartDate}/>
                    </div>
                    <div className={bookCardsStyles.formGroup}>
                      <label htmlFor="seriesEndDate">Series End Date:</label>
                      <input id="seriesEndDate" type="date" name="seriesEndDate" value={book.seriesEndDate}/>
                    </div>
                    {/* TAGS Section */}
                    <div className={bookCardsStyles.tagsSection}>
                      <div className={bookCardsStyles.formGroup}>
                        <div className={bookCardsStyles.tagsDisplay}>
                          {book.tags.map(tag => (
                            <span key={tag} className={bookCardsStyles.tag}>{tag}
                              <button type="button" className={buttonsStyles.removeTagBtn}>x</button>
                            </span>
                          ))}
                        </div>
                      </div>
                    </div>
                    {/* BUTTONS Section */}
                    <div className={bookCardsStyles.formActions}>
                      <Link to={`/editbook/${book._id}`} className={buttonsStyles.cancelButton}>Edit</Link>
                    </div>
                  </div>
                </div>
              ))}
            {/* </div> */}
          {/* </div> */}
        </div>
      {/* </div> */}
    </EmployeeLayout>
  );
}

export default InventoryPage;
